    def replace(self, string):
        if string is None:
            return string

        # Find numeric references and build result
        pattern = re.compile(r'&#(x?)([0-9A-Fa-f]+);')
        result = []
        last = 0
        for m in pattern.finditer(string):
            result.append(string[last:m.start()])
            prefix = m.group(1)
            digits = m.group(2)
            try:
