                    try:
                        reader.decrypt("")
                    except Exception:
                        pass
                if hasattr(reader, "getNumPages"):
                    for i in range(reader.getNumPages()):
                        p = reader.getPage(i)
                        txt = ""
                        if hasattr(p, "extractText"):
                            txt = p.extractText()
                        elif hasattr(p, "extract_text"):
                            txt = p.extract_text()
                        if txt:
